const b = $input.first().json.body || $input.first().json;
const allBinary = $input.first().binary || {};

let tasks = [];
try {
  tasks = JSON.parse(b.tasks || '[]');
} catch (_) {
  tasks = [];
}
if (!Array.isArray(tasks) || !tasks.length) {
  throw new Error('No tasks in payload — expected JSON array under field "tasks"');
}

const shared = {
  schedule_mode: b.schedule_mode || 'now',
  send_at: b.send_at || 'now',
  send_at_utc: b.send_at_utc || 'now',
  scope: b.scope || 'employee',
};

return tasks.map((t, idx) => {
  const emails = (Array.isArray(t.emails) ? t.emails : String(t.emails || '').split(/[,;]+/))
    .map(e => String(e).trim())
    .filter(e => /@/.test(e));
  const key = t.binary_key || ('file_' + (t.index != null ? t.index : idx));
  const fileBin = allBinary[key];
  return {
    json: {
      ...shared,
      task_index: idx,
      emails_array: emails,
      recipients_count: emails.length,
      subject: t.subject || 'תלוש שכר',
      body: t.body || '',
      body_html: t.body_html || ('<div dir="rtl">' + (t.body || '') + '</div>'),
      employee_number: t.employee_number || '',
      name: t.name || '',
      department: t.department || '',
      category: t.category || '',
      month: t.month || '',
      count: t.count || '',
      filename: t.filename || (fileBin && fileBin.fileName) || 'attachment.pdf',
    },
    binary: fileBin ? { data: fileBin } : {}
  };
});

function pickErr(item) {
  const out = (item && item.json) || {};
  if (out.error && typeof out.error === 'object') {
    const g = out.error;
    const msg = (typeof g.message === 'string' && g.message)
      || (g.message && typeof g.message === 'object' && g.message.error && g.message.error.message)
      || g.code;
    if (typeof msg === 'string' && msg.trim()) {
      return g.code && msg !== g.code ? (g.code + ': ' + msg) : msg;
    }
    try { return JSON.stringify(g).slice(0, 240); } catch (_) { return 'graph error'; }
  }
  if (typeof out.error === 'string' && out.error.trim()) return out.error;
  const e = item && item.error;
  if (!e) return null;
  if (typeof e === 'string') return e;
  const bodies = [];
  if (e.context) bodies.push(e.context.data, e.context.response, e.context.responseData);
  if (e.cause) {
    bodies.push(e.cause.body, e.cause.responseData, e.cause.data);
    if (e.cause.response) bodies.push(e.cause.response.data, e.cause.response.body, e.cause.response);
  }
  bodies.push(e.responseData, e.responseBody, e.lastResponse, e.errorResponse, e.data);
  if (e.response) bodies.push(e.response.data, e.response.body, e.response);
  for (let b of bodies) {
    if (!b) continue;
    if (typeof b === 'string') { try { b = JSON.parse(b); } catch (_) {} }
    if (b && typeof b === 'object') {
      const ge = b.error && typeof b.error === 'object' ? b.error : (b.code || b.message ? b : null);
      if (ge) {
        const code = ge.code || '';
        const m = (typeof ge.message === 'string' && ge.message) ||
                  (ge.message && typeof ge.message === 'object' && ge.message.error && ge.message.error.message) || '';
        if (code || m) return (code && m) ? (code + ': ' + m) : (code || m);
      }
    }
  }
  const desc = typeof e.description === 'string' ? e.description.trim() : '';
  const msg = typeof e.message === 'string' ? e.message.trim() : '';
  if (desc && msg && desc !== msg) return msg + ' — ' + desc;
  if (desc) return desc;
  if (msg) {
    const probe = ' [keys ctx=' + Object.keys(e.context||{}).join('|') + ' cause=' + Object.keys(e.cause||{}).join('|') + (e.cause && e.cause.response ? ' cresp=' + Object.keys(e.cause.response).join('|') : '') + ']';
    return msg + probe;
  }
  if (e.httpCode) return 'HTTP ' + e.httpCode;
  try { return JSON.stringify(e).slice(0, 240); } catch (_) {}
  return null;
}

const items = $input.all();
let split = [];
try { split = $('Split Out').all(); } catch (_) { split = items; }
const failures = [];
let ok = 0;
for (let i = 0; i < items.length; i++) {
  const msg = pickErr(items[i]);
  if (msg) {
    const orig = (split[i] && split[i].json) || (items[i] && items[i].json) || {};
    const out = (items[i] && items[i].json) || {};
    failures.push({
      email: orig.current_email || out.current_email || 'unknown',
      filename: orig.filename || out.filename || '',
      error: msg,
      http_code: (out.error && out.error.code) || (items[i].error && items[i].error.httpCode) || null
    });
  } else {
    ok++;
  }
}
const scheduleMode = (split[0] && split[0].json && split[0].json.schedule_mode) || (items[0] && items[0].json && items[0].json.schedule_mode) || 'now';
const total = items.length;
const status = failures.length === 0
  ? (scheduleMode === 'scheduled' ? 'scheduled' : 'sent')
  : (ok === 0 ? 'error' : 'partial');
return [{
  json: {
    status: status,
    sent: scheduleMode === 'now' ? ok : 0,
    scheduled: scheduleMode === 'scheduled' ? ok : 0,
    failed: failures.length,
    total: total,
    failures: failures,
    schedule_mode: scheduleMode,
    send_at_utc: (split[0] && split[0].json && split[0].json.send_at_utc) || 'now',
    scope: (split[0] && split[0].json && split[0].json.scope) || 'employee',
    recipients_count: total
  }
}];
